from itertools import combinations

class Solution:
    def evenSumSubgraphs(self, nums, edges):
        n = len(nums)
        count = 0
        for size in range(1, n + 1):
            for combo in combinations(range(n), size):
                if sum(nums[i] for i in combo) % 2 != 0:
                    continue
                s = set(combo)
                parent = {i: i for i in combo}

                def find(x):
                    while parent[x] != x:
                        parent[x] = parent[parent[x]]
                        x = parent[x]
                    return x

                for u, v in edges:
                    if u in s and v in s:
                        ru, rv = find(u), find(v)
                        if ru != rv:
                            parent[ru] = rv
                roots = {find(i) for i in combo}
                if len(roots) == 1:
                    count += 1
        return count

