class Solution:
    def evenSumSubgraphs(self, nums: list[int], edges: list[list[int]]) -> int:
        n = len(nums)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        count = 0
        for mask in range(1, 1 << n):
            total = 0
            nodes = []
            for i in range(n):
                if mask & (1 << i):
                    total += nums[i]
                    nodes.append(i)
            if total % 2 != 0:
                continue
            start = nodes[0]
            visited = 1 << start
            stack = [start]
            while stack:
                u = stack.pop()
                for v in adj[u]:
                    if (mask & (1 << v)) and not (visited & (1 << v)):
                        visited |= (1 << v)
                        stack.append(v)
            if visited == mask:
                count += 1
        return count

