var evenSumSubgraphs = function(nums, edges) {
    const n = nums.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    let count = 0;
    for (let mask = 1; mask < (1 << n); mask++) {
        let total = 0;
        const nodes = [];
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                total += nums[i];
                nodes.push(i);
            }
        }
        if (total % 2 !== 0) continue;
        const start = nodes[0];
        let visited = 1 << start;
        const stack = [start];
        while (stack.length > 0) {
            const u = stack.pop();
            for (const v of adj[u]) {
                if ((mask & (1 << v)) && !(visited & (1 << v))) {
                    visited |= (1 << v);
                    stack.push(v);
                }
            }
        }
        if (visited === mask) count++;
    }
    return count;
};
